// Fire 3 search queries per run for broader coverage.
// Time-based rotation: each 6-hour window starts at a different offset.
// With 14 queries and 3 per run, full keyword coverage every ~2 days.

const queries = [
  'data entry clerk',
  'operations coordinator',
  'manual reporting specialist',
  'spreadsheet management',
  'CRM coordinator',
  'invoicing specialist',
  'bookkeeper QuickBooks',
  'administrative assistant data entry',
  'accounts payable clerk',
  'order entry processor',
  'sales operations coordinator',
  'office coordinator CRM',
  'data migration specialist',
  'invoice processing clerk'
];

const SIX_HOURS_MS = 6 * 60 * 60 * 1000;
const baseIdx = Math.floor(Date.now() / SIX_HOURS_MS) % queries.length;

// Return 3 queries â€” the HTTP Request node will fire once per item
const selected = [];
for (let i = 0; i < 3; i++) {
  const idx = (baseIdx + i) % queries.length;
  selected.push({ json: { search_query: queries[idx], query_index: idx } });
}
return selected;

// Merge jobs from ALL API responses (multiple search queries per run).
// Clear accumulated results at pipeline start.
const staticData = $getWorkflowStaticData('global');
staticData._signalResults = [];

const items = $input.all();
if (!items || items.length === 0) {
  return [{ json: { _no_data: true, message: 'No input received' } }];
}

// Collect jobs from ALL API responses
const allJobs = [];
for (const item of items) {
  const inputJson = item.json;
  if (inputJson.data && Array.isArray(inputJson.data)) {
    for (const job of inputJson.data) {
      allJobs.push(job);
    }
  }
}

if (allJobs.length === 0) {
  return [{ json: { _no_data: true, message: 'All API responses returned 0 job listings' } }];
}

function cleanMarkdown(str) {
  if (!str) return '';
  return str
    .replace(/\*\*/g, '')
    .replace(/__/g, '')
    .replace(/^#+\s*/gm, '')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    .trim();
}

const jobBoardNames = [
  'remoterockethub', 'remote rockethub', 'remote rocket hub',
  'jobmatrix', 'totalh', 'talentify', 'jobrapido', 'jooble',
  'neuvoo', 'recruit.net', 'jobleads', 'careerjet', 'jobomas',
  'jobvertise', 'postjobfree', 'jobdiagnosis', 'lensa',
  'zippia', 'simplyhired', 'snagajob', 'whatjobs', 'jobcase',
  'arbeitnow', 'jobgether', 'adzuna', 'getwork',
  'talent.com', 'linkedin', 'indeed', 'glassdoor', 'ziprecruiter',
  'dice', 'monster', 'careerbuilder', 'hired', 'angel.co',
  'wellfound', 'remotive', 'weworkremotely', 'flexjobs',
  'remote.co', 'builtin', 'themuse', 'idealist',
  'virtualvocations', 'workingnomads', 'nodesk',
  'remotejobs', 'remote ok', 'remoteok', 'jobspresso',
  'pangian', 'dynamitejobs', 'himalayas', 'rocketpunch',
  'crossover', 'toptal', 'gun.io', 'andela', 'turing',
  'dailyremote'
];

const staffingAgencies = [
  'asg', 'robert half', 'randstad', 'adecco', 'manpower',
  'kelly services', 'hays', 'kforce', 'insight global',
  'teksystems', 'tek systems', 'apex systems', 'aerotek',
  'beacon hill', 'cybercoders', 'creative circle',
  'aquent', 'onward search', 'mastech', 'collabera',
  'infosys bpo', 'cognizant', 'wipro staffing',
  'allegis', 'expresspros', 'express employment',
  'spherion', 'volt', 'yoh', 'modis'
];

function isJobBoard(name) {
  if (!name) return false;
  const lower = name.toLowerCase().trim();
  for (const board of jobBoardNames) {
    if (lower.includes(board)) return true;
  }
  if (/^[a-z0-9][a-z0-9-]*\.[a-z]{2,}$/i.test(lower)) return true;
  return false;
}

function isStaffingAgency(name, companyType) {
  if (!name) return false;
  const lower = name.toLowerCase().trim();
  const typeL = (companyType || '').toLowerCase();
  if (typeL.includes('staffing') || typeL.includes('recruiting') || typeL.includes('placement')) return true;
  for (const agency of staffingAgencies) {
    if (lower === agency || lower.includes(agency)) return true;
  }
  return false;
}

function extractRealEmployer(description) {
  if (!description) return null;
  const patterns = [
    /(?:Company|Employer|Client|Organization)\s*:\s*([A-Z][A-Za-z0-9&'. -]{2,40})/i,
    /(?:Our client|our client),?\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:[,.]|\s+is)/i,
    /(?:on behalf of|partnered with|working with)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:[,.]|\s+to)/i,
    /([A-Z][A-Za-z0-9&'. -]{2,40})\s+is\s+(?:looking|hiring|seeking|searching)\s+(?:for|a|an)/,
    /(?:Work|work)\s+(?:at|for|with)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*[,!.]|\s*\n|\s+and\b)/,
    /(?:Welcome to|welcome to)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*[!.]|\s*\n)/,
    /(?:About|about)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*\n|\s*-|\s*:)/,
    /(?:Join|join)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s+as\b|\s+and\b|\s+today|!|,|\.|\s*\n)/
  ];

  const skipWords = [
    'the', 'our', 'this', 'that', 'your', 'their', 'some',
    'you', 'we', 'us', 'my', 'its', 'his', 'her', 'who',
    'what', 'when', 'where', 'how', 'why', 'all', 'any',
    'each', 'every', 'both', 'few', 'more', 'most', 'other',
    'remote', 'full time', 'part time', 'position', 'role',
    'team', 'department', 'company', 'organization', 'about',
    'summary', 'overview', 'description', 'responsibilities',
    'requirements', 'qualifications', 'benefits', 'salary',
    'join us', 'apply now', 'click here', 'learn more',
    'location', 'schedule', 'compensation', 'duties',
    'job summary', 'job description', 'job title',
    'equal opportunity', 'disclaimer'
  ];

  for (const pattern of patterns) {
    const match = description.match(pattern);
    if (match && match[1]) {
      const candidate = match[1].trim();
      if (candidate.length < 3) continue;
      const lower = candidate.toLowerCase();
      if (skipWords.includes(lower)) continue;
      if (isJobBoard(candidate)) continue;
      if (isInvalidCompanyName(candidate)) continue;
      if (candidate.split(/\s+/).length === 1 && lower.length < 5 && !/[A-Z]{2,}/.test(candidate)) continue;
      return candidate;
    }
  }
  return null;
}

// Data quality: filter company names that are actually skill/category tags
function isInvalidCompanyName(name) {
  if (!name) return true;
  const lower = name.toLowerCase().trim();
  // Common patterns where a skill/category gets misread as a company
  const skillTagPatterns = [
    /^(it|hr|qa|ui|ux)\s+(excel|word|testing|design|support|skills)/i,
    /^(microsoft|ms)\s+(excel|word|powerpoint|outlook|office|teams)/i,
    /^(google|apple|amazon)\s+(sheets|docs|drive|search)/i,
    /^(data|remote|online|digital|virtual)\s+(entry|work|job|position)/i
  ];
  for (const pattern of skillTagPatterns) {
    if (pattern.test(name)) return true;
  }
  return false;
}

function isSpamEmployer(name, website) {
  if (!name || name.length < 2) return true;
  if (isInvalidCompanyName(name)) return true;
  const lower = name.toLowerCase().trim();
  const ws = (website || '').toLowerCase();

  const invalidNames = [
    'you', 'we', 'us', 'they', 'them', 'me', 'he', 'she', 'it',
    'the', 'this', 'that', 'here', 'there', 'now', 'today',
    'who', 'what', 'when', 'where', 'how', 'why'
  ];
  if (invalidNames.includes(lower)) return true;

  const spamDomains = [
    'jobmatrix', 'totalh', 'jobrapido', 'jobomas',
    'jobvertise', 'postjobfree', 'jobdiagnosis',
    'zippia', 'salary.com', 'whatjobs', 'jobcase',
    'upwork', 'fiverr', 'freelancer'
  ];
  for (const spam of spamDomains) {
    if (lower.includes(spam) || ws.includes(spam)) return true;
  }
  if (/^[^a-zA-Z]*$/.test(name)) return true;
  if (lower.length <= 2 && !/^[a-z]{2}$/i.test(lower)) return true;
  const genericNames = [
    'work from home', 'remote position', 'hiring now', 'apply today',
    'urgent hiring', 'immediate start', 'easy work', 'home based',
    'online job', 'virtual assistant hiring'
  ];
  for (const generic of genericNames) {
    if (lower.includes(generic)) return true;
  }
  return false;
}

function buildLocation(city, state, country) {
  city = (city || '').trim();
  state = (state || '').trim();
  country = (country || '').trim();
  if (city && state) return city + ', ' + state;
  if (state) return state;
  if (city) return city;
  if (country) return country;
  return 'Remote / Not specified';
}

function pickBestUrl(job) {
  const applyLink = (job.job_apply_link || '').trim();
  const googleLink = (job.job_google_link || '').trim();
  const aggregatorDomains = [
    'dailyremote.com', 'remoterockethub.com', 'jooble.org',
    'talentify.io', 'jobrapido.com', 'neuvoo.com', 'adzuna.com',
    'getwork.com', 'lensa.com', 'zippia.com', 'whatjobs.com',
    'jobcase.com', 'arbeitnow.com', 'jobgether.com'
  ];
  function isGoogleFragment(url) {
    if (!url) return false;
    return url.includes('google.com/search') && (url.includes('#vhid=') || url.includes('udm=8'));
  }
  function isAggregator(url) {
    if (!url) return false;
    const lower = url.toLowerCase();
    for (const agg of aggregatorDomains) {
      if (lower.includes(agg)) return true;
    }
    return false;
  }
  if (applyLink && !isAggregator(applyLink) && !isGoogleFragment(applyLink)) return applyLink;
  if (googleLink && !isGoogleFragment(googleLink)) return googleLink;
  if (applyLink && !isGoogleFragment(applyLink)) return applyLink;
  if (applyLink) return applyLink;
  if (googleLink) return googleLink;
  return '';
}

const results = [];
for (const job of allJobs) {
  let companyName = cleanMarkdown(job.employer_name || '');
  const companyWebsite = (job.employer_website || '').trim();
  const rawDescription = job.job_description || '';
  const description = cleanMarkdown(rawDescription.substring(0, 2000));
  const title = cleanMarkdown(job.job_title || '');
  const companyType = (job.employer_company_type || '').trim();
  let employerSource = 'direct';

  if (isJobBoard(companyName)) {
    const extracted = extractRealEmployer(rawDescription);
    if (extracted) {
      companyName = extracted;
      employerSource = 'extracted_from_description';
    } else {
      continue;
    }
  } else if (isStaffingAgency(companyName, companyType)) {
    const extracted = extractRealEmployer(rawDescription);
    if (extracted) {
      employerSource = 'extracted_from_agency:' + companyName;
      companyName = extracted;
    } else {
      employerSource = 'staffing_agency';
    }
  }

  if (isSpamEmployer(companyName, companyWebsite)) continue;

  const city = (job.job_city || '').trim();
  const state = (job.job_state || '').trim();
  const country = (job.job_country || '').trim();

  results.push({
    json: {
      job_title: title,
      company_name: companyName,
      company_website: companyWebsite,
      job_description: description,
      job_city: city,
      job_state: state,
      job_country: country,
      job_location: buildLocation(city, state, country),
      employer_company_type: companyType,
      job_posting_url: pickBestUrl(job),
      date_posted: job.job_posted_at_datetime_utc || '',
      job_publisher: (job.job_publisher || '').trim(),
      employer_source: employerSource
    }
  });
}

if (results.length > 0) {
  return results;
}
return [{ json: { _no_data: true, message: 'All ' + allJobs.length + ' jobs filtered out' } }];

// Deduplication, pre-filtering, and title-based exclusion
const staticData = $getWorkflowStaticData('global');
if (!staticData._seenJobs) {
  staticData._seenJobs = {};
}

const now = Date.now();
const sevenDays = 7 * 24 * 60 * 60 * 1000;
for (const url of Object.keys(staticData._seenJobs)) {
  if (now - staticData._seenJobs[url] > sevenDays) {
    delete staticData._seenJobs[url];
  }
}

const excludeKeywords = [
  // Physical / blue collar
  'forklift', 'warehouse', 'nurse', 'nursing', 'construction',
  'truck driver', 'cdl', 'janitor', 'custodian', 'security guard',
  'electrician', 'plumber', 'hvac', 'welder', 'mechanic',
  'physical therapist', 'registered nurse', 'licensed practical',
  'certified nursing', 'phlebotom', 'radiology', 'surgical',
  'teacher', 'teaching', 'professor', 'sous chef', 'line cook',
  'barista', 'cashier', 'retail associate',
  // Scam / gig postings
  'research study', 'focus group', 'paid survey', 'paid studies',
  '$790/wk', '$800/wk', '$1000/wk', 'earn up to',
  'get paid to share your opinion', 'mystery shopper',
  'product testing', 'clinical trial', 'test products at home',
  'be your own boss', 'unlimited earning', 'work when you want',
  'side hustle', 'gig economy', 'flexible schedule with no',
  'anyone can apply', 'start immediately no experience',
  // Senior / strategic roles (NOT automation targets)
  'it manager', 'it operations manager', 'operations manager',
  'project manager', 'program manager', 'product manager',
  'director of', 'vice president', 'vp of',
  'head of it', 'head of operations', 'head of engineering',
  'chief information officer', 'chief technology officer',
  'chief operating officer', 'chief revenue officer',
  'systems administrator', 'network administrator',
  'network engineer', 'infrastructure engineer',
  'devops manager', 'security analyst', 'security engineer',
  // Engineering / dev roles
  'software developer', 'software engineer', 'frontend developer',
  'backend developer', 'full stack developer', 'full-stack developer',
  'devops engineer', 'solutions architect', 'principal engineer',
  'staff engineer', 'machine learning engineer', 'data scientist',
  'senior developer', 'lead developer', 'engineering manager',
  // QA / testing (not automation targets)
  'qa tester', 'qa engineer', 'quality assurance engineer',
  'test engineer', 'automation engineer',
  // Sales leadership
  'account executive', 'vp of sales', 'vice president of sales',
  'chief revenue officer', 'chief technology officer',
  'sales director', 'sales manager'
];

const items = $input.all();
const filtered = [];

for (const item of items) {
  // Skip sentinel items from Extract Job Data
  if (item.json._no_data || item.json._error) continue;

  const url = item.json.job_posting_url || '';
  const desc = (item.json.job_description || '').toLowerCase();
  const title = (item.json.job_title || '').toLowerCase();
  const company = (item.json.company_name || '').trim();
  const combined = title + ' ' + desc;

  if (!company || company.length < 2) continue;
  if (url && staticData._seenJobs[url]) continue;

  let excluded = false;
  for (const kw of excludeKeywords) {
    // For title-level exclusions (manager, director, vp), check title only
    // For description-level exclusions (scam, physical), check combined
    if (['it manager', 'it operations manager', 'operations manager',
         'project manager', 'program manager', 'product manager',
         'director of', 'vice president', 'vp of',
         'head of it', 'head of operations', 'head of engineering',
         'sales director', 'sales manager'].includes(kw)) {
      if (title.includes(kw)) { excluded = true; break; }
    } else {
      if (combined.includes(kw)) { excluded = true; break; }
    }
  }
  if (excluded) continue;

  if (url) {
    staticData._seenJobs[url] = now;
  }

  filtered.push(item);
}

return filtered.length > 0 ? filtered : [];

// ISSUE 6 FIX: Expanded tool detection with 60+ tools,
// searches title + description, and properly detects multiple tools.
const desc = ($json.job_description || '').toLowerCase();
const title = ($json.job_title || '').toLowerCase();
const combined = title + ' ' + desc;

const toolPatterns = [
