function isJobBoard(name) {
  if (!name) return false;
  const lower = name.toLowerCase().trim();
  for (const board of jobBoardNames) {
    if (lower.includes(board)) return true;
  }
  if (/^[a-z0-9][a-z0-9-]*\.[a-z]{2,}$/i.test(lower)) return true;
  return false;
}

function isStaffingAgency(name, companyType) {
  if (!name) return false;
  const lower = name.toLowerCase().trim();
  const typeL = (companyType || '').toLowerCase();
  if (typeL.includes('staffing') || typeL.includes('recruiting') || typeL.includes('placement')) return true;
  for (const agency of staffingAgencies) {
    if (lower === agency || lower.includes(agency)) return true;
  }
  return false;
}

function extractRealEmployer(description) {
  if (!description) return null;
  const patterns = [
    /(?:Company|Employer|Client|Organization)\s*:\s*([A-Z][A-Za-z0-9&'. -]{2,40})/i,
    /(?:Our client|our client),?\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:[,.]|\s+is)/i,
    /(?:on behalf of|partnered with|working with)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:[,.]|\s+to)/i,
    /([A-Z][A-Za-z0-9&'. -]{2,40})\s+is\s+(?:looking|hiring|seeking|searching)\s+(?:for|a|an)/,
    /(?:Work|work)\s+(?:at|for|with)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*[,!.]|\s*\n|\s+and\b)/,
    /(?:Welcome to|welcome to)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*[!.]|\s*\n)/,
    /(?:About|about)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s*\n|\s*-|\s*:)/,
    /(?:Join|join)\s+([A-Z][A-Za-z0-9&'. -]{2,40})(?:\s+as\b|\s+and\b|\s+today|!|,|\.|\s*\n)/
  ];

  const skipWords = [
    'the', 'our', 'this', 'that', 'your', 'their', 'some',
    'you', 'we', 'us', 'my', 'its', 'his', 'her', 'who',
    'what', 'when', 'where', 'how', 'why', 'all', 'any',
    'each', 'every', 'both', 'few', 'more', 'most', 'other',
    'remote', 'full time', 'part time', 'position', 'role',
    'team', 'department', 'company', 'organization', 'about',
    'summary', 'overview', 'description', 'responsibilities',
    'requirements', 'qualifications', 'benefits', 'salary',
    'join us', 'apply now', 'click here', 'learn more',
    'location', 'schedule', 'compensation', 'duties',
    'job summary', 'job description', 'job title',
    'equal opportunity', 'disclaimer'
  ];

  for (const pattern of patterns) {
    const match = description.match(pattern);
    if (match && match[1]) {
      const candidate = match[1].trim();
      if (candidate.length < 3) continue;
      const lower = candidate.toLowerCase();
      if (skipWords.includes(lower)) continue;
      if (isJobBoard(candidate)) continue;
      if (isInvalidCompanyName(candidate)) continue;
      if (candidate.split(/\s+/).length === 1 && lower.length < 5 && !/[A-Z]{2,}/.test(candidate)) continue;
      return candidate;
    }
  }
  return null;
}

// Data quality: filter company names that are actually skill/category tags
function isInvalidCompanyName(name) {
  if (!name) return true;
  const lower = name.toLowerCase().trim();
  // Common patterns where a skill/category gets misread as a company
  const skillTagPatterns = [
    /^(it|hr|qa|ui|ux)\s+(excel|word|testing|design|support|skills)/i,
    /^(microsoft|ms)\s+(excel|word|powerpoint|outlook|office|teams)/i,
    /^(google|apple|amazon)\s+(sheets|docs|drive|search)/i,
    /^(data|remote|online|digital|virtual)\s+(entry|work|job|position)/i
  ];
  for (const pattern of skillTagPatterns) {
    if (pattern.test(name)) return true;
  }
  return false;
}

function isSpamEmployer(name, website) {
  if (!name || name.length < 2) return true;
  if (isInvalidCompanyName(name)) return true;
  const lower = name.toLowerCase().trim();
  const ws = (website || '').toLowerCase();

  const invalidNames = [
    'you', 'we', 'us', 'they', 'them', 'me', 'he', 'she', 'it',
    'the', 'this', 'that', 'here', 'there', 'now', 'today',
    'who', 'what', 'when', 'where', 'how', 'why'
  ];
  if (invalidNames.includes(lower)) return true;

  const spamDomains = [
    'jobmatrix', 'totalh', 'jobrapido', 'jobomas',
    'jobvertise', 'postjobfree', 'jobdiagnosis',
    'zippia', 'salary.com', 'whatjobs', 'jobcase',
    'upwork', 'fiverr', 'freelancer'
  ];
  for (const spam of spamDomains) {
    if (lower.includes(spam) || ws.includes(spam)) return true;
  }
  if (/^[^a-zA-Z]*$/.test(name)) return true;
  if (lower.length <= 2 && !/^[a-z]{2}$/i.test(lower)) return true;
  const genericNames = [
    'work from home', 'remote position', 'hiring now', 'apply today',
    'urgent hiring', 'immediate start', 'easy work', 'home based',
    'online job', 'virtual assistant hiring'
  ];
  for (const generic of genericNames) {
    if (lower.includes(generic)) return true;
  }
  return false;
}

function buildLocation(city, state, country) {
  city = (city || '').trim();
  state = (state || '').trim();
  country = (country || '').trim();
  if (city && state) return city + ', ' + state;
  if (state) return state;
  if (city) return city;
  if (country) return country;
  return 'Remote / Not specified';
}

function pickBestUrl(job) {
  const applyLink = (job.job_apply_link || '').trim();
  const googleLink = (job.job_google_link || '').trim();
  const aggregatorDomains = [
    'dailyremote.com', 'remoterockethub.com', 'jooble.org',
    'talentify.io', 'jobrapido.com', 'neuvoo.com', 'adzuna.com',
    'getwork.com', 'lensa.com', 'zippia.com', 'whatjobs.com',
    'jobcase.com', 'arbeitnow.com', 'jobgether.com'
  ];
  function isGoogleFragment(url) {
    if (!url) return false;
    return url.includes('google.com/search') && (url.includes('#vhid=') || url.includes('udm=8'));
  }
  function isAggregator(url) {
    if (!url) return false;
    const lower = url.toLowerCase();
    for (const agg of aggregatorDomains) {
      if (lower.includes(agg)) return true;
    }
    return false;
  }
  if (applyLink && !isAggregator(applyLink) && !isGoogleFragment(applyLink)) return applyLink;
  if (googleLink && !isGoogleFragment(googleLink)) return googleLink;
  if (applyLink && !isGoogleFragment(applyLink)) return applyLink;
  if (applyLink) return applyLink;
  if (googleLink) return googleLink;
  return '';
}

