// ISSUE 1 FIX: Parse AI response and merge with job data from Detect Tech Stack.
// Uses HTTP Request response format: choices[0].message.content

let content = '';
const input = $json;

// Handle OpenAI API HTTP response format
if (input.choices && input.choices[0] && input.choices[0].message) {
  content = String(input.choices[0].message.content || '');
} else if (input.message && input.message.content) {
  content = String(input.message.content);
} else if (input.text) {
  content = String(input.text);
}

const clean = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

// Get the original job data from Detect Tech Stack node
let job = {};
try {
  job = $('Detect Tech Stack').item.json || {};
} catch(e) {
  try {
    job = $('Process One By One').item.json || {};
  } catch(e2) {
    job = {};
  }
}

let score = 0;
let cat = 'Unknown';
let reason = 'No response';
let size = 'Unknown';
let suggest = 'N/A';
let outreach = '';

try {
  const m = clean.match(/\{[\s\S]*\}/);
  if (m) {
    const p = JSON.parse(m[0]);
    score = parseInt(p.automation_score, 10) || 0;
    cat = String(p.pain_category || 'Unknown');
    reason = String(p.reasoning || '');
    size = String(p.estimated_company_size || 'Unknown');
    suggest = String(p.automation_suggestion || '');
    outreach = String(p.outreach_message || '');
  }
} catch(e) {
  reason = 'Parse error: ' + e.message;
}

if (score < 0) score = 0;
if (score > 10) score = 10;
if (score <= 2) outreach = 'N/A';

return {
  json: {
    job_title: String(job.job_title || ''),
    company_name: String(job.company_name || ''),
    company_website: String(job.company_website || ''),
    job_description: String(job.job_description || ''),
    job_city: String(job.job_city || ''),
    job_state: String(job.job_state || ''),
    job_location: String(job.job_location || ''),
    job_posting_url: String(job.job_posting_url || ''),
    employer_company_type: String(job.employer_company_type || ''),
    detected_tools: String(job.detected_tools || ''),
    detected_tool_count: Number(job.detected_tool_count || 0),
    employer_source: String(job.employer_source || 'direct'),
    automation_score: score,
    pain_category: cat,
    reasoning: reason,
    estimated_company_size: size,
    automation_suggestion: suggest,
    outreach_message: outreach,
    detected_date: new Date().toISOString().split('T')[0]
  }
};

// Accumulate each processed result into staticData
const staticData = $getWorkflowStaticData('global');
if (!staticData._signalResults) {
  staticData._signalResults = [];
}

const item = $json;

staticData._signalResults.push({
  job_title: String(item.job_title || ''),
  company_name: String(item.company_name || ''),
  company_website: String(item.company_website || ''),
  job_description: String(item.job_description || ''),
  job_city: String(item.job_city || ''),
  job_state: String(item.job_state || ''),
  job_location: String(item.job_location || ''),
  job_posting_url: String(item.job_posting_url || ''),
  employer_company_type: String(item.employer_company_type || ''),
  detected_tools: String(item.detected_tools || ''),
  detected_tool_count: Number(item.detected_tool_count || 0),
  employer_source: String(item.employer_source || 'direct'),
  automation_score: Number(item.automation_score) || 0,
  pain_category: String(item.pain_category || ''),
  reasoning: String(item.reasoning || ''),
  estimated_company_size: String(item.estimated_company_size || ''),
  automation_suggestion: String(item.automation_suggestion || ''),
  outreach_message: String(item.outreach_message || ''),
  detected_date: String(item.detected_date || new Date().toISOString().split('T')[0])
});

return { json: { accumulated: true, count: staticData._signalResults.length } };

// ISSUE 1 FIX: Collect all accumulated results after the batch loop completes.
// SplitInBatches output 0 fires when ALL batches are done.
const staticData = $getWorkflowStaticData('global');
const results = staticData._signalResults || [];

// Clear for next run
staticData._signalResults = [];

if (results.length === 0) {
  return [{ json: { _no_results: true, automation_score: 0 } }];
}

return results.map(item => ({ json: item }));

// Build email alert â€” only for score >= 8 (hot leads per guideline)
const items = $input.all();
const hotLeads = items.filter(item => (Number(item.json.automation_score) || 0) >= 8);

if (hotLeads.length === 0) {
  return [{ json: { has_hot_leads: false, count: 0, subject: '', html: '' } }];
}

let html = '<h2>\uD83D\uDD25 ' + hotLeads.length + ' Hot Automation Prospect(s) Detected!</h2>';
html += '<p>The following leads scored <strong>8+/10</strong> on the automation opportunity scale:</p><hr/>';

for (const lead of hotLeads) {
  const j = lead.json;
  html += '<div style="margin-bottom:20px;padding:15px;border:1px solid #ddd;border-radius:8px;">';
  html += '<h3>' + (j.company_name || 'Unknown') + ' \u2014 ' + (j.job_title || 'Unknown') + '</h3>';
  if (j.employer_source && j.employer_source !== 'direct') {
    html += '<p style="color:#e67e22;"><strong>\u26A0\uFE0F Note:</strong> Company name was ' + j.employer_source + '</p>';
  }
  html += '<p><strong>Location:</strong> ' + (j.job_location || 'Not specified') + '</p>';
  html += '<p><strong>AI Score:</strong> ' + j.automation_score + '/10</p>';
  html += '<p><strong>Pain Category:</strong> ' + (j.pain_category || '') + '</p>';
  html += '<p><strong>Company Size:</strong> ' + (j.estimated_company_size || '') + '</p>';
  html += '<p><strong>Detected Tools (' + (j.detected_tool_count || 0) + '):</strong> ' + (j.detected_tools || 'None') + '</p>';
  html += '<p><strong>Why this is hot:</strong> ' + (j.reasoning || '') + '</p>';
  html += '<p><strong>Suggested automation:</strong> ' + (j.automation_suggestion || '') + '</p>';
  if (j.outreach_message && j.outreach_message !== 'N/A') {
    html += '<p><strong>\uD83D\uDCE7 Outreach:</strong> <em>' + j.outreach_message + '</em></p>';
  }
  html += '<p><a href="' + (j.job_posting_url || '#') + '">View Original Posting</a>';
  if (j.company_website) {
    html += ' | <a href="' + j.company_website + '">Company Website</a>';
  }
  html += '</p>';
  html += '</div>';
}

html += '<hr/><p><strong>\uD83D\uDC49 Action:</strong> Review these prospects and consider outreach.</p>';

const subject = hotLeads.length === 1
  ? '\uD83D\uDD25 Hot Prospect: ' + hotLeads[0].json.company_name + ' (Score: ' + hotLeads[0].json.automation_score + '/10)'
  : '\uD83D\uDD25 ' + hotLeads.length + ' Hot Prospects Detected (Scores 8+/10)';

return [{ json: { has_hot_leads: true, count: hotLeads.length, subject: subject, html: html } }];
